// Centralised typed access to the parsed dataset.
// All JSON is generated by scripts/parse-chat.ts and committed to src/data/.
import statsJson from "../data/stats.json";
import membersJson from "../data/members.json";
import leaderboardsJson from "../data/leaderboards.json";
import dailyJson from "../data/daily.json";
import vocabJson from "../data/vocab.json";
import pairsJson from "../data/pairs.json";
import shipsJson from "../data/ships.json";
import nameSagaJson from "../data/name-saga.json";
import curseWallJson from "../data/curse-wall.json";
import emmaSagaJson from "../data/emma-saga.json";
import hofJson from "../data/hall-of-fame.json";
import unhingedJson from "../data/unhinged.json";
import beefJson from "../data/beef.json";
import awardsJson from "../data/awards.json";
import monthlyJson from "../data/monthly.json";
import messagesIndexJson from "../data/messages-index.json";

export type Stats = {
  totalMessages: number;
  totalMedia: number;
  totalDeleted: number;
  lateNight: number;
  daysCovered: number;
  hourHist: number[];
  monthHist: Array<[string, number]>;
  firstTs: number;
  lastTs: number;
  memberCount: number;
};

export type Member = {
  name: string;
  initials: string;
  color: string;
  messageCount: number;
  profanity: number;
  lateNight: number;
  deleted: number;
  media: number;
  allCaps: number;
  avgLen: number;
  peakHour: number;
  hourHist: number[];
  firstTs: number | null;
  lastTs: number | null;
  topWords: Array<[string, number]>;
  topEmoji: Array<[string, number]>;
  summary: string;
};

export type Leaderboards = {
  activity: Array<[string, number]>;
  profanity: Array<[string, number]>;
  lateNight: Array<[string, number]>;
  deleted: Array<[string, number]>;
  media: Array<[string, number]>;
  allCaps: Array<[string, number]>;
};

export type Daily = Array<{
  date: string;
  count: number;
  drama: number;
  topQuote: { author: string; text: string; ts: number } | null;
}>;

export type Vocab = {
  words: Array<[string, number]>;
  emoji: Array<[string, number]>;
};

export type Pairs = Array<{ from: string; to: string; count: number }>;
export type Ships = Array<{ a: string; b: string; count: number }>;

export type NameSaga = Array<{
  ts: number; date: string; by: string; from: string; to: string;
}>;

export type Quote = { id?: number; ts: number; date?: string; author: string; text: string; isMedia?: boolean; isDeleted?: boolean; isSystem?: boolean; hour?: number };

export type Hof = { longest: Quote[]; shouty: Quote[]; cursed: Quote[] };

export type Unhinged = Array<{ ts: number; date: string; messages: Quote[] }>;
export type Beef = Array<{ a: string; b: string; score: number; sample: Quote[] }>;
export type Award = { id: string; title: string; desc: string; winner: Array<[string, number]> };
export type Monthly = Array<{
  month: string; count: number;
  topAuthors: Array<[string, number]>;
  topQuote: { author: string; text: string; ts: number } | null;
  defining: string; mood: string;
}>;

export const stats = statsJson as unknown as Stats;
export const members = membersJson as unknown as Member[];
export const leaderboards = leaderboardsJson as unknown as Leaderboards;
export const daily = dailyJson as unknown as Daily;
export const vocab = vocabJson as unknown as Vocab;
export const pairs = pairsJson as unknown as Pairs;
export const ships = shipsJson as unknown as Ships;
export const nameSaga = nameSagaJson as unknown as NameSaga;
export const curseWall = curseWallJson as unknown as Quote[];
export const emmaSaga = emmaSagaJson as unknown as Quote[];
export const hof = hofJson as unknown as Hof;
export const unhinged = unhingedJson as unknown as Unhinged;
export const beef = beefJson as unknown as Beef;
export const awards = awardsJson as unknown as Award[];
export const monthly = monthlyJson as unknown as Monthly;
export const messagesIndex = messagesIndexJson as unknown as Array<{ month: string; count: number }>;

export const memberMap = new Map(members.map((m) => [m.name, m]));

export const colorOf = (name: string) =>
  memberMap.get(name)?.color ?? "#888";

export const initialsOf = (name: string) => {
  const m = memberMap.get(name);
  if (m) return m.initials;
  return name.replace(/[^A-Za-z0-9]/g, "").slice(0, 2).toUpperCase() || "??";
};

// Lazy-load monthly message chunks
const monthCache = new Map<string, Promise<Quote[]>>();
export async function loadMonth(month: string): Promise<Quote[]> {
  if (!monthCache.has(month)) {
    monthCache.set(
      month,
      import(`../data/messages/${month}.json`).then((m) => m.default as Quote[]),
    );
  }
  return monthCache.get(month)!;
}

export async function loadAllMessages(): Promise<Quote[]> {
  const chunks = await Promise.all(messagesIndex.map((mi) => loadMonth(mi.month)));
  return chunks.flat();
}

// Search index lazy
let searchIndexPromise: Promise<Record<string, number[]>> | null = null;
export function loadSearchIndex(): Promise<Record<string, number[]>> {
  if (!searchIndexPromise) {
    searchIndexPromise = import("../data/search-index.json").then((m) => m.default as Record<string, number[]>);
  }
  return searchIndexPromise;
}

export const fmtDate = (ts: number) => {
  const d = new Date(ts);
  return d.toLocaleDateString("en-GB", { day: "2-digit", month: "short", year: "numeric" });
};
export const fmtTime = (ts: number) => {
  const d = new Date(ts);
  return `${String(d.getUTCHours()).padStart(2, "0")}:${String(d.getUTCMinutes()).padStart(2, "0")}`;
};
export const fmtDateTime = (ts: number) => `${fmtDate(ts)} ${fmtTime(ts)}`;
